        <form action={signout}>
          <button type="submit" style={{ padding: "6px 12px", cursor: "pointer" }}>
            Sign out
          </button>
        </form>
      </div>
      <DashboardClient
        bookmarks={bookmarks ?? []}
        totalPages={totalPages}
        currentPage={page}
        currentQ={q}
        currentFilter={filter}
      />
    </div>
  );
