              >
                <div className="shrink-0 w-8 h-8 rounded-lg bg-[#f5f2ee] flex items-center justify-center overflow-hidden">
                  {bm.favicon_url ? (
                    <img src={bm.favicon_url} width={18} height={18} alt="" />
                  ) : (
                    <span className="text-[#aaa] text-xs">🔗</span>
                  )}
                </div>

                <div className="flex-1 min-w-0">
                  <a
                    href={bm.url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-sm font-medium text-[#222] hover:text-[#c2732a] transition-colors truncate block"
                  >
                    {bm.title}
                  </a>
                  <div className="flex items-center gap-2 mt-0.5">
                    <span className="text-xs text-[#aaa] truncate">{new URL(bm.url).hostname}</span>
                    <span className="text-[#ddd]">·</span>
                    <span className="text-xs text-[#aaa]">{new Date(bm.created_at).toLocaleDateString("en-US")}</span>
